/**
 * 연계메시지 등록 화면으로 이동한다.
 *
 * @param searchVO 검색조건
 * @param cntcMessage
 * @param model
 * @return "egovframework/com/ssi/syi/ims/EgovCntcMessageRegist"
 * @throws Exception
 */
@RequestMapping(value = "/ssi/syi/ims/addCntcMessage.do", params = "!cmd")
public String insertCntcMessageView(@ModelAttribute("searchVO") CntcMessageVO searchVO,
		@ModelAttribute("cntcMessage") CntcMessage cntcMessage,
		ModelMap model) throws Exception {
	// 연계메시지 리스트박스 데이터
	CntcMessageVO searchCntcMessageVO = new CntcMessageVO();
	searchCntcMessageVO.setRecordCountPerPage(999999);
	searchCntcMessageVO.setFirstIndex(0);
	searchCntcMessageVO.setSearchCondition("CodeList");
	List<EgovMap> cntcMessageList = cntcMessageService.selectCntcMessageList(searchCntcMessageVO);
	model.addAttribute("cntcMessageList", cntcMessageList);

	return "egovframework/com/ssi/syi/ims/EgovCntcMessageRegist";
}

/**
 * 연계메시지를 등록한다.
 *
 * @param searchVO 검색조건
 * @param cntcMessage
 * @param bindingResult
 * @param model
 * @return "egovframework/com/ssi/syi/ims/EgovCntcMessageRegist"
 * @throws Exception
 */
@RequestMapping(value = "/ssi/syi/ims/addCntcMessage.do", params = "cmd=Regist")
public String insertCntcMessage(@ModelAttribute("searchVO") CntcMessageVO searchVO,
		@Valid @ModelAttribute("cntcMessage") CntcMessage cntcMessage,
		BindingResult bindingResult, ModelMap model) throws Exception {

	if (bindingResult.hasErrors()) {
		// 연계메시지 리스트박스 데이터
		CntcMessageVO searchCntcMessageVO = new CntcMessageVO();
		searchCntcMessageVO.setRecordCountPerPage(999999);
		searchCntcMessageVO.setFirstIndex(0);
		searchCntcMessageVO.setSearchCondition("CodeList");
		List<EgovMap> cntcMessageList = cntcMessageService.selectCntcMessageList(searchCntcMessageVO);
		model.addAttribute("cntcMessageList", cntcMessageList);

		return "egovframework/com/ssi/syi/ims/EgovCntcMessageRegist";
	}

	// 로그인VO에서 사용자 정보 가져오기
	LoginVO loginVO = (LoginVO) EgovUserDetailsHelper.getAuthenticatedUser();
	String uniqId = loginVO == null ? "" : EgovStringUtil.isNullToString(loginVO.getUniqId());
	cntcMessage.setFrstRegisterId(uniqId);

	// ID Generation
	String sCntcMessageId = idgenService.getNextStringId();
	cntcMessage.setCntcMessageId(sCntcMessageId);

	cntcMessageService.insertCntcMessage(cntcMessage);
	return "forward:/ssi/syi/ims/getCntcMessageList.do";
}

